class Solution {
public:
    vector<int> pivotArray(vector<int>& nums, int pivot) {
        sort(nums.begin(), nums.end());
        vector<int> result;
        for (int i = 0; i < nums.size(); i++) {
            if (nums[i] == pivot) {
                result.push_back(nums[i]);
            } else if (nums[i] < pivot) {
                result.insert(result.end(), nums.begin() + i, nums.begin() + i + 1);
            } else {
                result.insert(result.end(), nums.begin() + i + 1, nums.end());
            }
        }
        return result;
    }
};
